/**
 * Token Estimator — Issue #1478
 *
 * Content-aware token estimation for tool outputs. Replaces the flat
 * `text.length / 4` approximation with divisors calibrated by content
 * kind. Still a heuristic (no real BPE), but meaningfully more accurate
 * for the JSON-heavy and code-heavy outputs that dominate MCP and
 * search-tool results.
 *
 * At 1M context, 10% estimation error = 100k token miscount, large
 * enough to flip nudge decisions. Downstream issues #1475, #1479,
 * #1480 all depend on this being tighter than char/4.
 *
 * Calibration reference:
 *   - prose      (divisor 4.0):  English text, Claude tokenizer averages ~4 chars/token
 *   - code       (divisor 3.5):  source code has more symbols / short identifiers
 *   - json       (divisor 3.0):  repeated keys, braces, quotes compress into more tokens
 *   - image      (divisor 0):    can't measure — logs separately
 *   - unknown    (divisor 4.0):  fallback matches old char/4 behavior
 *
 * `estimateTokens` is pure; `detectContentKind` inspects tool name + a
 * small sample of the text and returns the best guess.
 */

export type ContentKind = 'prose' | 'code' | 'json' | 'image' | 'unknown';

const DIVISORS: Record<ContentKind, number> = {
  prose: 4.0,
  code: 3.5,
  json: 3.0,
  image: 0,
  unknown: 4.0,
};

const CODE_TOOLS = new Set(['Read', 'Grep', 'Glob']);
const SAMPLE_LENGTH = 256;

/**
 * Estimate tokens from a text string and content kind. Returns 0 for
 * empty input and for image content (images are tokenized at a rate
 * we can't derive from the base64 character length — separate telemetry).
 */
export function estimateTokens(text: string | null | undefined, kind: ContentKind = 'unknown'): number {
  if (!text) return 0;
  const divisor = DIVISORS[kind];
  if (divisor <= 0) return 0;
  return Math.ceil(text.length / divisor);
}

/**
 * Classify a tool output by content kind. Fast path on tool name, then
 * structural inspection of a small sample. Never returns `image` from
 * text-only inputs unless the sample clearly contains a base64 image
 * marker.
 */
export function detectContentKind(toolName: string | undefined, sample: string | null | undefined): ContentKind {
  // Empty / unknown
  if (!sample) return 'unknown';
  const head = sample.slice(0, SAMPLE_LENGTH).trim();

  // Image detection first — high specificity, avoids misclassifying
  // base64 payloads as JSON even when they appear inside a JSON wrapper.
  if (head.startsWith('data:image/') || head.includes('"type":"image"') || /^iVBORw0KGgo|^\/9j\/|^R0lGOD/.test(head)) {
    return 'image';
  }

  // MCP tool name → JSON (MCP responses are JSON-shaped)
  if (toolName?.startsWith('mcp__')) return 'json';

  // Read/Grep/Glob → code (even when reading prose Markdown, the tokenizer
  // behavior is closer to code than to plain English because of symbol density)
  if (toolName && CODE_TOOLS.has(toolName)) return 'code';

  // Structural JSON detection
  if ((head.startsWith('{') && head.includes('"')) || (head.startsWith('[') && head.includes(','))) {
    return 'json';
  }

  // Agent / Bash / Skill and unknown tools default to prose
  return 'prose';
}

/**
 * Convenience: extract text content from the various shapes a PostToolUse
 * `input` object may carry. Keeps the caller one import lighter.
 */
export function extractToolOutputText(input: {
  tool_result?: string | { content?: string; is_error?: boolean } | unknown;
  tool_output?: unknown;
  output?: string;
}): string {
  const { tool_result, tool_output, output } = input;
  if (typeof tool_result === 'string') return tool_result;
  if (
    tool_result &&
    typeof tool_result === 'object' &&
    'content' in tool_result &&
    typeof (tool_result as { content?: unknown }).content === 'string'
  ) {
    return (tool_result as { content: string }).content;
  }
  if (typeof output === 'string') return output;
  if (tool_output !== undefined) {
    try {
      return JSON.stringify(tool_output) ?? '';
    } catch {
      return '';
    }
  }
  return '';
}
